UPDATE public.garden_import_queue SET payload = '{"species": "Chestnut", "species_slug": "chestnut", "varieties": [{"name": "Reilly 🌱", "slug": "reilly", "lineage_type": "indigenous", "climate_slug": "humid-subtropical", "origin": "Alstonville Plateau, NSW, Australia (early 1900s)", "traits": "Low chill, medium-large nut, light brown, free-falling", "flesh_fruit": "", "yield_notes": "Prolific bearer, Feb-March ripening (early)", "growing_notes": "SPECIFICALLY DEVELOPED FOR SUBTROPICAL BRISBANE. Indigenous Australian selection from Alstonville near Brisbane. Low chill performs well in subtropical conditions. Requires well-drained soil to minimize Phytophthora.", "availability": "Daley''s Fruit Tree Nursery (Kyogle, NSW), Subtropical Fruit Club of Qld", "sort_order": 0}, {"name": "George Sands (Alstonville) 🌱", "slug": "george-sands-alstonville", "lineage_type": "indigenous", "climate_slug": "humid-subtropical", "origin": "Alstonville Plateau, NSW, Australia", "traits": "Large, low-chill, subtropical adaptation", "flesh_fruit": "", "yield_notes": "Sets well alone, benefits from cross-pollination", "growing_notes": "Local Alstonville selection performing well in subtropics. Indigenous to Brisbane''s subtropical region. Adapted to warm, humid conditions with proper drainage.", "availability": "Daley''s Fruit Tree Nursery, Queensland specialty nurseries", "sort_order": 1}, {"name": "April Gold", "slug": "april-gold", "lineage_type": "open_pollinated", "climate_slug": "humid-subtropical", "origin": "Dandenong Ranges, Victoria (early selection, European origin)", "traits": "Extra large dark colored nuts, upright habit, free-falling", "flesh_fruit": "", "yield_notes": "Good yielder, early variety", "growing_notes": "", "availability": "", "sort_order": 2}, {"name": "Japanese Chestnut (Seedling)", "slug": "japanese-chestnut-seedling", "lineage_type": "open_pollinated", "climate_slug": "humid-subtropical", "origin": "Japan/Korea, naturalized selections", "traits": "Small to medium tree (10-15m), spreading, tolerates heat and humidity", "flesh_fruit": "", "yield_notes": "Heavy production, early bearing (3-5 years)", "growing_notes": "BEST HEAT TOLERANCE of all chestnuts. Grown successfully in subtropical Brazil. Naturally resistant to blight and ink disease. MOST SUITABLE SPECIES for Brisbane subtropical conditions. Barely deciduous in warm climates. Tolerates summer heat and humidity better than European types.", "availability": "Specialty nurseries, Route 9 Cooperative (imported seed)", "sort_order": 3}, {"name": "Abundance", "slug": "abundance", "lineage_type": "open_pollinated", "climate_slug": "humid-subtropical", "origin": "China, selected for nut production", "traits": "Medium tree (12-18m), spreading", "flesh_fruit": "", "yield_notes": "Prolific, begins 4-5 years", "growing_notes": "", "availability": "", "sort_order": 4}, {"name": "Crane", "slug": "crane", "lineage_type": "open_pollinated", "climate_slug": "humid-subtropical", "origin": "China, selected cultivar", "traits": "Vigorous", "flesh_fruit": "", "yield_notes": "Good commercial producer", "growing_notes": "Blight resistant. Heat and drought tolerant. SUITABLE for Brisbane with proper drainage.", "availability": "Chinese chestnut nurseries", "sort_order": 5}, {"name": "Sleeping Giant", "slug": "sleeping-giant", "lineage_type": "open_pollinated", "climate_slug": "humid-subtropical", "origin": "USA (Connecticut), Dick Jaynes selection", "traits": "Larger than species, early ripening", "flesh_fruit": "", "yield_notes": "Reliable producer", "growing_notes": "Highly blight resistant (Chinese heritage). MARGINAL for Brisbane - prefers cooler but worth trial in cooler microclimates.", "availability": "Red Fern Farm, specialty nurseries", "sort_order": 6}, {"name": "Colossal", "slug": "colossal", "lineage_type": "hybrid", "climate_slug": "humid-subtropical", "origin": "USA, European/Asian hybrid", "traits": "Very large nuts, vigorous", "flesh_fruit": "", "yield_notes": "High producer, begins early (3-4 years)", "growing_notes": "Blight resistant. Hybrid vigor provides some heat adaptation. POTENTIAL for Brisbane but untested in true subtropical conditions.", "availability": "Nativ Nurseries, specialty growers", "sort_order": 7}, {"name": "AU Homestead", "slug": "au-homestead", "lineage_type": "hybrid", "climate_slug": "humid-subtropical", "origin": "USA (Auburn University), Chinese/American hybrid", "traits": "Compact tree, spreading habit", "flesh_fruit": "", "yield_notes": "Early bearing, productive", "growing_notes": "", "availability": "", "sort_order": 8}, {"name": "Moreton Bay Chestnut (Black Bean)", "slug": "moreton-bay-chestnut-black-bean", "lineage_type": "indigenous", "climate_slug": "humid-subtropical", "origin": "Queensland coast (Moreton Bay), Northern NSW, Indigenous to Brisbane", "traits": "Large evergreen tree (35-45 ft cultivated), beautiful pinnate leaves, red-yellow flowers", "flesh_fruit": "", "yield_notes": "Ornamental tree, seeds traditionally used by Aboriginal peoples after processing", "growing_notes": "INDIGENOUS TO BRISBANE REGION. Species: Castanospermum australe (NOT true chestnut - Fabaceae family). Native to tropical and subtropical Queensland. Perfectly adapted to Brisbane climate. Aboriginal food source for thousands of years. Seeds contain toxic saponins requiring traditional processing. Valuable timber. Now susceptible to shot hole borer. Not for casual consumption - traditional knowledge required.", "availability": "Australian native plant nurseries, Queensland nurseries", "sort_order": 9}, {"name": "Malabar Chestnut (Guiana Chestnut)", "slug": "malabar-chestnut-guiana-chestnut", "lineage_type": "open_pollinated", "climate_slug": "humid-subtropical", "origin": "Central/South America, tropical regions", "traits": "Semi-deciduous tree, spectacular red-brown flowers, large woody pods", "flesh_fruit": "", "yield_notes": "Precocious, heavy cropping in subtropical areas", "growing_notes": "EXCELLENT FOR BRISBANE SUBTROPICAL. Species: Pachira insignis/glabra (NOT true chestnut - Malvaceae family). Tolerates frost inland from Bundaberg. Grown successfully in Brisbane area. Frost-free location preferred. Full sun to partial shade. Well-drained soil. Requires frequent watering. Not a true chestnut but produces edible nuts after proper preparation.", "availability": "Daley''s Fruit Tree Nursery, tropical plant nurseries", "sort_order": 10}, {"name": "WATER CHESTNUTS - TRADITIONAL INDIAN CULTIVATION", "slug": "water-chestnuts-traditional-indian-cultivation", "lineage_type": "indigenous", "climate_slug": "tropical-monsoon", "origin": "", "traits": "", "flesh_fruit": "", "yield_notes": "", "growing_notes": "", "availability": "", "sort_order": 0}, {"name": "Singhara / Singara (Water Chestnut) 🏆", "slug": "singhara-singara-water-chestnut", "lineage_type": "heirloom", "climate_slug": "tropical-monsoon", "origin": "Indigenous to India - traditional crop in Bihar, West Bengal, Jharkhand, Kerala backwaters", "traits": "Aquatic floating plant, grows in ponds/wetlands, black/green horned nuts with 2-4 spines", "flesh_fruit": "", "yield_notes": "4-12 tonnes/hectare. Bihar Large Red: 7 t/ha. Green Spineless: up to 12 t/ha", "growing_notes": "Species: Trapa natans (Lythraceae - aquatic annual, NOT a tree). EXCELLENT FOR KERALA WETLANDS/BACKWATERS. Indigenous traditional Indian crop. Grows in tropical/subtropical freshwater. Called ''cooling food'' - beats summer heat. Used medicinally (anti-diabetic, anti-inflammatory). Thrives in monsoon. Farmers grow fish for half year, then water chestnuts. pH 6.7-8.2 ideal. Planted at monsoon beginning. Traditional Ayurvedic use. Made into flour, used fresh. Perfectly adapted to Kerala''s wetland agriculture. Can be integrated with traditional paddy field/backwater farming systems.", "availability": "", "sort_order": 1}, {"name": "Chinese Water Chestnut", "slug": "chinese-water-chestnut", "lineage_type": "open_pollinated", "climate_slug": "tropical-monsoon", "origin": "China, Southeast Asia, grown in parts of India", "traits": "Rush-like plant, produces underground tubers (corms), brown chestnut-colored skin", "flesh_fruit": "", "yield_notes": "Good yields in suitable wetlands", "growing_notes": "Species: Eleocharis dulcis (Cyperaceae - sedge/rush, grows tubers). SUITABLE for Kerala aquatic cultivation. Grows in freshwater ponds. Different from Singhara (Trapa) - this is tuber not nut. Used extensively in Asian cooking. Crisp texture retained when cooked. High in fiber. Good for tropical wetland farming.", "availability": "Asian vegetable suppliers, specialty aquatic plant nurseries", "sort_order": 2}, {"name": "Indian Chestnut (Java Olive)", "slug": "indian-chestnut-java-olive", "lineage_type": "indigenous", "climate_slug": "tropical-monsoon", "origin": "Native to India, Southeast Asia. Indigenous to Kerala and Western Ghats", "traits": "Large tropical deciduous tree, big leathery leaves, unique star-shaped fruit pods", "flesh_fruit": "", "yield_notes": "Good tropical producer", "growing_notes": "Species: Sterculia foetida (Malvaceae family). EXCELLENT FOR KERALA/THIRUVALLA. Indigenous to India including Kerala. Perfectly adapted to tropical monsoon climate. Fast-growing, drought-resistant after establishment. Pest-resistant. Valuable timber (durable wood). Traditional medicine use (bark, leaves, seeds - Ayurvedic). Seeds edible after roasting. Used in local cuisines. Thrives in Kerala''s heat and humidity. Important reforestation tree. Soil conservation (extensive roots). Cultural significance - gathering spot, sometimes sacred. Well-adapted to monsoon rainfall patterns.", "availability": "Greenverz, Kerala Forest Department nurseries, Indian native plant suppliers", "sort_order": 3}, {"name": "Malabar Chestnut (Pachira)", "slug": "malabar-chestnut-pachira", "lineage_type": "indigenous", "climate_slug": "tropical-monsoon", "origin": "Central/South America, widely grown in India including Kerala, Karnataka, Tamil Nadu (Western Ghats)", "traits": "Evergreen tropical tree (up to 50 ft), glossy dark green leaves, spectacular white flowers, semi-deciduous", "flesh_fruit": "", "yield_notes": "Good tropical producer", "growing_notes": "Species: Pachira insignis/glabra (Malvaceae family). EXCELLENT FOR KERALA/THIRUVALLA. Grown extensively in Western Ghats of Kerala, Karnataka, Tamil Nadu. Perfectly adapted to warm tropical climate with plenty of rainfall - ideal for monsoon regions. Best harvested in dry season (ripe fruits). Well-suited to Thiruvalla''s conditions. Requires warm climate, can tolerate some frost. Prefers full sun to partial shade. Well-drained soil essential. Used for desserts, snacks. Quality nuts have glossy bright-brown color. Can be stored 2 months cool/dry, or frozen 6 months. Ornamental value (beautiful flowers). Seeds raw not recommended (prepare first).", "availability": "Kerala nurseries, Western Ghats plant suppliers, tropical nurseries throughout India", "sort_order": 4}, {"name": "2. Indian Chestnut (Sterculia foetida) - Native Kerala species", "slug": "2-indian-chestnut-sterculia-foetida-native-kerala-species", "lineage_type": "indigenous", "climate_slug": "tropical-monsoon", "origin": "", "traits": "", "flesh_fruit": "", "yield_notes": "", "growing_notes": "", "availability": "", "sort_order": 5}, {"name": "3. Malabar Chestnut (Pachira) - Western Ghats cultivation", "slug": "3-malabar-chestnut-pachira-western-ghats-cultivation", "lineage_type": "indigenous", "climate_slug": "tropical-monsoon", "origin": "", "traits": "", "flesh_fruit": "", "yield_notes": "", "growing_notes": "", "availability": "", "sort_order": 6}], "variety_count": 18}'::jsonb,
  variety_count = 18, status = 'parsed'
WHERE source_path = 'brainstorm-inbox/import-payloads/chestnut.json';

