UPDATE public.garden_import_queue SET payload = '{"species": "Clove", "species_slug": "clove", "varieties": [{"name": "Standard Clove (Syzygium aromaticum)", "slug": "standard-clove-syzygium-aromaticum", "lineage_type": "open_pollinated", "climate_slug": "humid-subtropical", "origin": "Native to Moluccas (Maluku Islands), Indonesia", "traits": "Evergreen tree, 8-12m height, glossy oval leaves, small pale pink flowers clustered at branch tips", "flesh_fruit": "", "yield_notes": "Zero to minimal in Brisbane climate. Trees begin flowering at 7-8 years (IF conditions met), full bearing at 15+ years. Brisbane''s climate will prevent flowering.", "growing_notes": "", "availability": "Rarely available in Australian nurseries. Some specialist tropical plant nurseries may carry seedlings. Not readily available in Brisbane due to climatic unsuitability.", "sort_order": 0}, {"name": "1. Zanzibar Type", "slug": "1-zanzibar-type", "lineage_type": "open_pollinated", "climate_slug": "tropical-monsoon", "origin": "Originally from Zanzibar/Pemba Islands (Tanzania), introduced to India in 19th century, now widely cultivated in Kerala", "traits": "Smaller, slender buds compared to Penang type. Dark brown color when dried. Medium-sized tree with good branching habit.", "flesh_fruit": "", "yield_notes": "High productivity - 2-8 kg/tree/year. Known for better adaptability and consistent yields.", "growing_notes": "", "availability": "Widely available through Kerala Agricultural University, ICAR centers, certified nurseries in Kottayam and Kollam districts, Kerala State Spices Development Board.", "sort_order": 0}, {"name": "2. Penang Type", "slug": "2-penang-type", "lineage_type": "open_pollinated", "climate_slug": "tropical-monsoon", "origin": "Penang, Malaysia; introduced to India via spice trade routes", "traits": "Large, plump buds. Reddish-brown color. Vigorous tree growth.", "flesh_fruit": "", "yield_notes": "Moderate productivity - 2-5 kg/tree/year. Prized for appearance and export quality.", "growing_notes": "", "availability": "Available from specialized spice nurseries, Kerala Agricultural University research stations, limited commercial availability compared to Zanzibar.", "sort_order": 1}, {"name": "3. Amboyan Type", "slug": "3-amboyan-type", "lineage_type": "open_pollinated", "climate_slug": "tropical-monsoon", "origin": "Ambon Island, Maluku Islands, Indonesia (original native region of clove)", "traits": "Large, plump buds similar to Penang. Strong aromatic properties.", "flesh_fruit": "", "yield_notes": "Slightly lower productivity than Zanzibar - 2-4 kg/tree/year.", "growing_notes": "", "availability": "Limited availability in Kerala. May be sourced through specialized collectors or direct import of planting material from Indonesia.", "sort_order": 2}, {"name": "4. Burliar-1 Selection", "slug": "4-burliar-1-selection", "lineage_type": "open_pollinated", "climate_slug": "tropical-monsoon", "origin": "Selected from Burliar region, Nilgiris, Tamil Nadu (1850s cultivation zone). One of the first clove introductions to South India.", "traits": "High-yielding selection adapted to South Indian conditions. Medium-sized tree.", "flesh_fruit": "", "yield_notes": "2-8 kg/tree/year (average 2-5 kg). Consistent bearer.", "growing_notes": "", "availability": "Available from Tamil Nadu Agricultural University, Kerala Agricultural University, certified nurseries in Kerala-Tamil Nadu border regions.", "sort_order": 3}, {"name": "5. KC-1 (King Clove-1)", "slug": "5-kc-1-king-clove-1", "lineage_type": "open_pollinated", "climate_slug": "tropical-monsoon", "origin": "Tamil Nadu selection, bolder flower bud variant identified in Kanyakumari district", "traits": "King type - larger, bolder flower buds than standard cloves. Robust tree structure.", "flesh_fruit": "", "yield_notes": "Moderate - 2-5 kg/tree/year, but higher value per kg due to size.", "growing_notes": "", "availability": "Tamil Nadu Agricultural University, Kanyakumari district nurseries, some Kerala nurseries near Tamil Nadu border.", "sort_order": 4}, {"name": "6. KC-2 (King Clove-2)", "slug": "6-kc-2-king-clove-2", "lineage_type": "open_pollinated", "climate_slug": "tropical-monsoon", "origin": "Tamil Nadu selection, another bold bud variant from Kanyakumari", "traits": "Similar to KC-1, bold flower buds, slightly different tree morphology.", "flesh_fruit": "", "yield_notes": "2-5 kg/tree/year.", "growing_notes": "", "availability": "Same as KC-1 sources.", "sort_order": 5}, {"name": "7. LC-1 (Lilliput/Mini Clove)", "slug": "7-lc-1-lilliput-mini-clove", "lineage_type": "open_pollinated", "climate_slug": "tropical-monsoon", "origin": "Tamil Nadu selection, normal/mini clove variant", "traits": "Smaller stature tree, smaller buds, spreading growth habit.", "flesh_fruit": "", "yield_notes": "Lower weight per tree (1.5-3 kg/tree/year) but may be suitable for denser planting.", "growing_notes": "", "availability": "Limited. Tamil Nadu nurseries, some experimental stations.", "sort_order": 6}, {"name": "8. Kanyakumari Clove (GI Tagged) 🏆", "slug": "8-kanyakumari-clove-gi-tagged", "lineage_type": "heirloom", "climate_slug": "tropical-monsoon", "origin": "Kanyakumari district, Tamil Nadu, Western Ghats. Introduced in early 1800s by East India Company at Courtallam. Geographical Indication (GI) tagged variety.", "traits": "Grown at 400-900m elevation in black soil rich in organic nutrients. High essential oil concentration. Characteristic aroma and rich flavor. Strong antioxidant properties.", "flesh_fruit": "", "yield_notes": "2-6 kg/tree/year. Kanyakumari district produces 80% of India''s total clove production.", "growing_notes": "", "availability": "Kanyakumari district nurseries, Kerala State Spices Development Board, certified through GI registry sources.", "sort_order": 7}, {"name": "9. Tuni Clove (Maluku Endemic) 🌏", "slug": "9-tuni-clove-maluku-endemic", "lineage_type": "heirloom", "climate_slug": "tropical-monsoon", "origin": "Native to Ambon Island, Maluku Islands, Indonesia. Ancient indigenous variety.", "traits": "Larger leaf, fruit, and seed morphology compared to other varieties. High eugenol content in buds (67.9%), stems (80.6%), and leaves (60.5%).", "flesh_fruit": "", "yield_notes": "Variable in non-native conditions. 2-5 kg/tree/year if well-adapted.", "growing_notes": "", "availability": "", "sort_order": 8}, {"name": "10. Afo Clove (Maluku Endemic) 🌏", "slug": "10-afo-clove-maluku-endemic", "lineage_type": "heirloom", "climate_slug": "tropical-monsoon", "origin": "Native to Ternate Island, North Maluku Province, Indonesia. Ancient indigenous variety.", "traits": "Endemic Maluku variety with distinct morphological characteristics. Different from Tuni variety in tree structure and bud formation.", "flesh_fruit": "", "yield_notes": "Variable in non-native conditions.", "growing_notes": "", "availability": "", "sort_order": 9}, {"name": "11. Siputih Variety", "slug": "11-siputih-variety", "lineage_type": "indigenous", "climate_slug": "tropical-monsoon", "origin": "Hiri Island, Ternate, North Maluku, Indonesia. Local indigenous variety.", "traits": "Local adaptation to Hiri Island conditions.", "flesh_fruit": "", "yield_notes": "Adapted to local conditions.", "growing_notes": "", "availability": "", "sort_order": 10}, {"name": "12. Posi-posi Variety", "slug": "12-posi-posi-variety", "lineage_type": "indigenous", "climate_slug": "tropical-monsoon", "origin": "Hiri Island, Ternate, North Maluku, Indonesia. Local indigenous variety.", "traits": "Local adaptation to Hiri Island conditions.", "flesh_fruit": "", "yield_notes": "Adapted to local conditions.", "growing_notes": "", "availability": "", "sort_order": 11}, {"name": "13. Raja Clove (King Clove - Maluku)", "slug": "13-raja-clove-king-clove-maluku", "lineage_type": "indigenous", "climate_slug": "tropical-monsoon", "origin": "Native to Ambon Island, Maluku. Traditional ''king'' type with distinctive morphology.", "traits": "Characterized by distinct morphological features specific to Ambon genetics.", "flesh_fruit": "", "yield_notes": "Variable.", "growing_notes": "", "availability": "", "sort_order": 12}, {"name": "14. Forest Clove (Maluku Wild Type) 🌏", "slug": "14-forest-clove-maluku-wild-type", "lineage_type": "heirloom", "climate_slug": "tropical-monsoon", "origin": "Wild/forest populations in Ambon and Seram Islands, Moluccas. Ancient wild genetic stock.", "traits": "Wild type with natural variation. Characterized across 54 morpho-agronomical characteristics. Represents genetic diversity of original clove populations.", "flesh_fruit": "", "yield_notes": "Variable, wild populations not selected for production.", "growing_notes": "", "availability": "Not commercially available. Research/conservation germplasm only.", "sort_order": 13}, {"name": "15. Madagascar Clove Types", "slug": "15-madagascar-clove-types", "lineage_type": "open_pollinated", "climate_slug": "tropical-monsoon", "origin": "Madagascar (introduced from Moluccas via French smuggling operations in 1770s). Madagascar is now world''s leading clove exporter.", "traits": "Smaller buds than Sri Lankan types, stronger flavor suited for cooking. Categorized as CGI (Handpick), CG2 (Prima), CG3 (Courant). High oil content due to growing conditions.", "flesh_fruit": "", "yield_notes": "Madagascar has very high productivity zones. Individual tree yields 3-8 kg/year.", "growing_notes": "", "availability": "", "sort_order": 14}, {"name": "16. Sri Lankan Clove Types", "slug": "16-sri-lankan-clove-types", "lineage_type": "open_pollinated", "climate_slug": "tropical-monsoon", "origin": "Sri Lanka (introduced historically through Arab traders or colonial powers). Cultivated in Kandyan Forest Gardens in Kandy, Kegalle, and Matale districts.", "traits": "Grown in mixed home gardens (Kandyan Forest Gardens) alongside pepper, nutmeg, and cinnamon. Larger buds than Madagascar types, milder flavor. Sun-dried processing.", "flesh_fruit": "", "yield_notes": "Lower productivity - average 250 kg/hectare. Harvest October-January.", "growing_notes": "", "availability": "Limited. Would require import from Sri Lankan sources or through regional spice networks. Kerala''s proximity to Sri Lanka makes cultural exchange possible.", "sort_order": 15}, {"name": "17. Pemba Clove (Zanzibar Archipelago)", "slug": "17-pemba-clove-zanzibar-archipelago", "lineage_type": "heirloom", "climate_slug": "tropical-monsoon", "origin": "Pemba Island, Zanzibar Archipelago, Tanzania. Some of the world''s oldest clove trees. Introduced from Moluccas in early 1800s.", "traits": "Hand-picked at last moment before flowering for maximum size and mature flavor. Bright pink when ripe, turn brown as they dry. Significantly higher essential oil content (15-18%) than other world regions. Large cloves with strong aroma and intense taste. Used locally as natural anesthetic substitute.", "flesh_fruit": "", "yield_notes": "Very high - up to 40 kg/tree/year for well-grown trees (exceptional trees up to 80 kg/year). Much higher than Indian averages.", "growing_notes": "", "availability": "Very limited. Pemba cloves are premium export product. Planting material would require specialized import through spice research institutions.", "sort_order": 16}, {"name": "18. Sulawesi/Minahasa Clove (Indonesia)", "slug": "18-sulawesi-minahasa-clove-indonesia", "lineage_type": "indigenous", "climate_slug": "tropical-monsoon", "origin": "Sulawesi, particularly Minahasa region, Indonesia. Major Indonesian clove production area (Sulawesi produces 40%+ of Indonesian cloves).", "traits": "Strong, pungent flavor similar to Moluccas types. Valued in traditional spice blends.", "flesh_fruit": "", "yield_notes": "High productivity region.", "growing_notes": "", "availability": "", "sort_order": 17}], "variety_count": 19}'::jsonb,
  variety_count = 19, status = 'parsed'
WHERE source_path = 'brainstorm-inbox/import-payloads/clove.json';

UPDATE public.garden_import_queue SET payload = '{"species": "Coconut", "species_slug": "coconut", "varieties": [{"name": "Malayan Dwarf (All Colors)", "slug": "malayan-dwarf-all-colors", "lineage_type": "open_pollinated", "climate_slug": "humid-subtropical", "origin": "Malaysia, introduced late 1800s", "traits": "Medium-sized tree (30-60 feet), compact growth, early bearing in 3-4 years. Available in Yellow, Green, Golden/Orange, and Red varieties based on fruit color.", "flesh_fruit": "", "yield_notes": "60-100 nuts per year once established", "growing_notes": "Suitable for Brisbane''s subtropical climate with protection. Requires warm, sheltered position, free-draining soil, and deep organic mulch. Resistant to Lethal Yellowing disease. Best planted in coastal locations; will tolerate temperatures to -3°C but unlikely to fruit south of northern NSW.", "availability": "Daley''s Fruit Tree Nursery (Queensland), Oxley Nursery Brisbane, specialized palm nurseries", "sort_order": 0}, {"name": "Dwarf Hybrid (Solomon Islands selection)", "slug": "dwarf-hybrid-solomon-islands-selection", "lineage_type": "hybrid", "climate_slug": "humid-subtropical", "origin": "Solomon Islands, with some selections from North Queensland", "traits": "High-yielding precocious hybrid, flowers in 3rd year, fruits in 4th year in moist tropical conditions. Moderate-sized fruit with large volume-to-husk ratio.", "flesh_fruit": "", "yield_notes": "High productivity once established", "growing_notes": "Will grow outside the tropics in warm, sheltered position. Worth trying in coastal locations as far south as Coffs Harbour, NSW. Requires free-draining soil and deep organic mulch. Suitable for Brisbane''s warmer suburbs with frost protection.", "availability": "Daley''s Fruit Tree Nursery (Queensland)", "sort_order": 1}, {"name": "Maypan Hybrid", "slug": "maypan-hybrid", "lineage_type": "hybrid", "climate_slug": "humid-subtropical", "origin": "Jamaica, 1960s (Malayan Dwarf × Panama Tall)", "traits": "Medium-sized tree to 60 feet, cold-hardy for a coconut, disease-resistant especially to Lethal Yellowing. Combines hardiness of Malayan Dwarf with weather resistance of Panama Tall.", "flesh_fruit": "", "yield_notes": "Good productivity, 80-100 nuts per year", "growing_notes": "", "availability": "", "sort_order": 2}, {"name": "Fiji Dwarf", "slug": "fiji-dwarf", "lineage_type": "open_pollinated", "climate_slug": "humid-subtropical", "origin": "Fiji, selected for disease resistance in 1970s", "traits": "Unique dwarf with swollen bole at base, slower-growing, distinctive thick crooked trunk, compact height to 25 feet. Shorter, wider leaflets create fuller canopy.", "flesh_fruit": "", "yield_notes": "Moderate, 50-70 nuts per year", "growing_notes": "Selected for resistance to Lethal Yellowing disease. Suitable for Brisbane with protection, especially in warmer coastal suburbs. Compact size makes harvesting easier. Requires warm microclimate and frost protection.", "availability": "Specialty palm nurseries", "sort_order": 3}, {"name": "Native Niu Kafa Type (Historical)", "slug": "native-niu-kafa-type-historical", "lineage_type": "heirloom", "climate_slug": "humid-subtropical", "origin": "Indigenous to Australia, documented in historical records from Four Mile Beach Port Douglas (1908), Russell Island, and other Queensland coastal areas", "traits": "Tall upright crown shape (distinct from spreading niu vai varieties). Long, angular three-sided nuts with thick husk adapted for oceanic dispersal. Some dwarf phenotypes exist with unique Australian characteristics.", "flesh_fruit": "", "yield_notes": "Variable, generally lower than cultivated varieties", "growing_notes": "", "availability": "", "sort_order": 4}, {"name": "Panama Tall (Pacific Tall)", "slug": "panama-tall-pacific-tall", "lineage_type": "open_pollinated", "climate_slug": "humid-subtropical", "origin": "Panama/Pacific region", "traits": "Large tree to 100 feet, exceptional hardiness and cold tolerance for coconut. Most cold-resistant variety available. Excellent wind resistance.", "flesh_fruit": "", "yield_notes": "80-100 nuts per year", "growing_notes": "", "availability": "", "sort_order": 5}, {"name": "West Coast Tall (WCT)", "slug": "west-coast-tall-wct", "lineage_type": "heirloom", "climate_slug": "tropical-monsoon", "origin": "Indigenous to India, cultivated since ancient times along west coast", "traits": "", "flesh_fruit": "", "yield_notes": "", "growing_notes": "", "availability": "", "sort_order": 0}, {"name": "Kuttiyadi (WCT Ecotype)", "slug": "kuttiyadi-wct-ecotype", "lineage_type": "heirloom", "climate_slug": "tropical-monsoon", "origin": "Kuttiyadi region, Kozhikode District, Kerala - ecotype of West Coast Tall", "traits": "Tall palm adapted to hilly midland regions, distinct genetic makeup from other WCT due to local environmental factors (climate, pH, rainfall). Matures in 5 years (faster than standard WCT).", "flesh_fruit": "", "yield_notes": "Higher nut yield than standard WCT", "growing_notes": "Indigenous Kerala ecotype adapted to midland regions with different environmental conditions than coastal WCT. Developed over generations through natural selection in Kuttiyadi''s specific terroir. Represents local agrobiodiversity. Excellent for Thiruvalla area which is inland.", "availability": "Kerala Agricultural University, regional nurseries in Kozhikode/Calicut area", "sort_order": 1}, {"name": "East Coast Tall (ECT)", "slug": "east-coast-tall-ect", "lineage_type": "heirloom", "climate_slug": "tropical-monsoon", "origin": "East coast of India (Tamil Nadu, Andhra Pradesh, Odisha)", "traits": "Tall variety 50-90 feet, thrives in well-drained sandy loam, alluvial and red loamy soils. Distinct orange color on young nuts. Tolerates inland conditions better than WCT.", "flesh_fruit": "", "yield_notes": "60-70 nuts per year, starts bearing 6-8 years", "growing_notes": "Well-balanced water and meat content, excellent for both tender coconut water and mature processing. Moderately tolerant to pests (bugs, mites, insects). More tolerant of inland conditions than WCT, making it suitable for areas slightly away from coast. Good choice for Thiruvalla''s inland location.", "availability": "Available in Kerala from Coconut Development Board, government nurseries", "sort_order": 2}, {"name": "Lakshadweep Ordinary (LCT / Chandrakalpa)", "slug": "lakshadweep-ordinary-lct-chandrakalpa", "lineage_type": "heirloom", "climate_slug": "tropical-monsoon", "origin": "Lakshadweep Islands, introduced to Indian mainland in 1940", "traits": "Moderate height 11.6 meters, stem girth 80cm. Grows in all soil types, excellent moisture stress tolerance. Long productive life 50-80 years.", "flesh_fruit": "", "yield_notes": "100 nuts per palm annually, starts flowering 6 years after planting", "growing_notes": "Extremely versatile - grows well in all soil types from sandy beaches to inland areas. Superior toddy production makes it valuable for traditional Kerala toddy/jaggery industry. High humidity and salt spray tolerance. Perfect for Kerala''s monsoon climate. Recommended throughout Kerala, Karnataka, Tamil Nadu.", "availability": "Coconut Development Board, Kerala Agricultural University, government nurseries throughout Kerala", "sort_order": 3}, {"name": "Tiptur Tall (TPT)", "slug": "tiptur-tall-tpt", "lineage_type": "heirloom", "climate_slug": "tropical-monsoon", "origin": "Tiptur region, Karnataka, India", "traits": "Tall variety, very low maintenance, one of easiest coconuts to grow. Large leathery fronds.", "flesh_fruit": "", "yield_notes": "70-80 coconuts per year, starts bearing 6-7 years after planting", "growing_notes": "Famous for minimal maintenance requirements. Reliable year-after-year production. Well-suited to Kerala''s climate. Good choice for low-input farming.", "availability": "Available in Kerala from agricultural departments, regional nurseries", "sort_order": 4}, {"name": "Andaman Ordinary Tall", "slug": "andaman-ordinary-tall", "lineage_type": "heirloom", "climate_slug": "tropical-monsoon", "origin": "Andaman & Nicobar Islands", "traits": "Very tall variety up to 30 meters, robust growth, good toddy yielder", "flesh_fruit": "", "yield_notes": "Good productivity", "growing_notes": "Farmers plant in large numbers especially in Karnataka. Well-adapted to island and coastal tropical conditions, performs well in Kerala''s monsoon climate.", "availability": "Government nurseries, Coconut Development Board", "sort_order": 5}, {"name": "Chowghat Orange Dwarf (COD / Chenthangu)", "slug": "chowghat-orange-dwarf-cod-chenthangu", "lineage_type": "indigenous", "climate_slug": "tropical-monsoon", "origin": "Kerala, India - known as ''Chenthangu'' in Malayalam", "traits": "True dwarf variety 12-16 feet height, early flowering 3-4 years. Round to almost-round fruits with smooth orange skin when ripe. Compact size ideal for small holdings.", "flesh_fruit": "", "yield_notes": "65-112 nuts per palm annually", "growing_notes": "", "availability": "", "sort_order": 6}, {"name": "Chowghat Green Dwarf (CGD)", "slug": "chowghat-green-dwarf-cgd", "lineage_type": "indigenous", "climate_slug": "tropical-monsoon", "origin": "Kerala, India", "traits": "Dwarf variety with dark green leaves, petioles, and nuts. Takes 3-4 years to bear.", "flesh_fruit": "", "yield_notes": "66 nuts per palm per year", "growing_notes": "Recommended for Kerala tender coconut production. Distinctive all-green appearance. Well-adapted to Kerala''s monsoon conditions.", "availability": "Kerala Agricultural University, ICAR-CPCRI, Coconut Development Board nurseries", "sort_order": 7}, {"name": "Chowghat Yellow Dwarf", "slug": "chowghat-yellow-dwarf", "lineage_type": "open_pollinated", "climate_slug": "tropical-monsoon", "origin": "Kerala, India", "traits": "Smallest coconut tree variety, vibrant yellow-colored coconuts", "flesh_fruit": "", "yield_notes": "Good yield for dwarf type", "growing_notes": "Highly resistant to diseases and pests. Easier maintenance. Perfect for small gardens and home cultivation in Kerala.", "availability": "Kerala nurseries, agricultural departments", "sort_order": 8}, {"name": "Chowghat Red Dwarf", "slug": "chowghat-red-dwarf", "lineage_type": "open_pollinated", "climate_slug": "tropical-monsoon", "origin": "Kerala, India", "traits": "Dwarf variety 25-30 feet height, distinctive red-tinged nuts. Thrives in various soil types including sandy and loamy.", "flesh_fruit": "", "yield_notes": "Up to 150 coconuts annually", "growing_notes": "Excellent pest and disease resistance. Low-maintenance option. Prized for sweet water and distinctive appearance. Ideal for Kerala''s humid tropical climate.", "availability": "Kerala Agricultural University, specialized nurseries", "sort_order": 9}, {"name": "Gangabondam (Gangabondam Green Dwarf)", "slug": "gangabondam-gangabondam-green-dwarf", "lineage_type": "open_pollinated", "climate_slug": "tropical-monsoon", "origin": "Andhra Pradesh, India", "traits": "", "flesh_fruit": "", "yield_notes": "", "growing_notes": "", "availability": "", "sort_order": 10}, {"name": "Malayan Yellow Dwarf (MYD)", "slug": "malayan-yellow-dwarf-myd", "lineage_type": "open_pollinated", "climate_slug": "tropical-monsoon", "origin": "Malaysia, introduced to India", "traits": "Medium dwarf 30-50 feet, pale yellow petioles and mature fruit. Early bearing 3-4 years, 50-year lifespan.", "flesh_fruit": "", "yield_notes": "Good productivity in tropical climates", "growing_notes": "Widely grown globally, performs excellently in Kerala''s hot tropical climate. High yields in consistently hot areas. Disease resistant. Ideal for Kerala''s monsoon conditions with high heat and humidity.", "availability": "Available from Greens of Kerala, Indian Glorious Nursery, Kerala nurseries", "sort_order": 11}, {"name": "Malayan Green Dwarf", "slug": "malayan-green-dwarf", "lineage_type": "open_pollinated", "climate_slug": "tropical-monsoon", "origin": "Malaysia", "traits": "Shorter 